    // ドット絵（マス目データ）をビットマップとして描画する共通処理。
    // grid の値: 0=何も描かない(透明), 1=線の色, 2=塗りの色
    public static class PixelArt
    {
        static readonly Random _rand = new();

        public static Bitmap Render(int[,] grid, int pixelSize, Color lineColor, Color fillColor)
        {
            int rows = grid.GetLength(0);
            int cols = grid.GetLength(1);
            var bmp = new Bitmap(cols * pixelSize, rows * pixelSize);

            using (var g = Graphics.FromImage(bmp))
            {
                g.Clear(Color.Transparent);

                for (int y = 0; y < rows; y++)
                {
                    for (int x = 0; x < cols; x++)
                    {
                        Color? color = grid[y, x] switch
                        {
                            1 => lineColor,
                            2 => fillColor,
                            _ => null
                        };
                        if (color != null)
                        {
                            using var brush = new SolidBrush(color.Value);
                            g.FillRectangle(brush, x * pixelSize, y * pixelSize, pixelSize, pixelSize);
                        }
                    }
                }
            }

            return bmp;
        }

