        // カテゴリ名 → 3パターンの設計図。
        // 肉と乳製品は本物の絵に対応済み。それ以外は本物の絵ができるまで仮で埋めている。
        // 絵ができ次第、各カテゴリの配列を専用の設計図に差し替える。
        public static readonly Dictionary<string, List<int[,]>> CharacterSets = new()
        {
            ["肉"] = new List<int[,]> { MeatPattern1, MeatPattern2, MeatPattern3 },
            ["魚"] = new List<int[,]> { FishPattern1, FishPattern2, FishPattern3 },
            ["野菜"] = new List<int[,]> { VegetablePattern1, VegetablePattern1, VegetablePattern1 },
            ["乳製品"] = new List<int[,]> { DairyPattern1, DairyPattern2, DairyPattern3 },
            ["卵"] = new List<int[,]> { EggPattern1, EggPattern2, EggPattern3 },
            ["その他"] = new List<int[,]> { MeatPattern1, MeatPattern1, MeatPattern1 },
            // ゾンビ（期限切れ）状態専用のキャラ。カテゴリに関係なく、期限切れの食材はこちらを表示する。
            // 絵ができるまでは仮で肉の絵を流用している。
            ["ゾンビ"] = new List<int[,]> { ZombiePattern1, ZombiePattern1, ZombiePattern1 },
        };

        // カテゴリ名を渡すと、そのカテゴリの3パターンから毎回ランダムに1つ選んで返す。
        // 該当カテゴリが無ければ「その他」を使う。
        public static int[,] GetRandomPattern(string category)
        {
            var patterns = CharacterSets.TryGetValue(category, out var p) ? p : CharacterSets["その他"];
            return patterns[_rand.Next(patterns.Count)];
        }

        // カテゴリ名を渡すと、そのカテゴリのパターン1（固定）を返す。図鑑など毎回同じ絵にしたい場面で使う。
        // 該当カテゴリが無ければ「その他」を使う。
        public static int[,] GetFirstPattern(string category)
        {
            var patterns = CharacterSets.TryGetValue(category, out var p) ? p : CharacterSets["その他"];
            return patterns[0];
        }
    }
}
